import { Injectable } from '@angular/core';
import { Observable, from, interval } from 'rxjs';
import { filter, map, switchMap, take } from 'rxjs/operators';
import { BaseService } from './base.service';
import { GeneratedReport } from '../models';

@Injectable({ providedIn: 'root' })
export class GeneratedReportsService extends BaseService<GeneratedReport> {
  protected tableName = 'generated_reports';

  /**
   * Restituisce la lista dei report generati da un utente specifico (o azienda),
   * ordinati dal più recente.
   */
  getReportsForUser(userId: string, companyId: string): Observable<GeneratedReport[]> {
    // Converti la Promise in Observable con 'from'
    return from(
      this.supabase
        .from(this.tableName)
        .select('*')
        .eq('user_id', userId)
        .eq('company_id', companyId)
        .order('generated_at', { ascending: false })
        .then(result => result.data as GeneratedReport[])
    );
  }

  /**
   * Polling per attendere che un report sia stato generato (generated_at non null).
   * Restituisce l'intero record quando disponibile.
   */
  waitForReport(reportId: string, intervalMs = 2000): Observable<GeneratedReport> {
    return interval(intervalMs).pipe(
      // Inizia subito (0) e poi ogni intervalMs
      switchMap(() => from(
        this.supabase
          .from(this.tableName)
          .select('*')
          .eq('id', reportId)
          .maybeSingle()
          .then(result => result.data as GeneratedReport | null)
      )),
      // Filtra solo i record esistenti e già generati
      filter(report => report !== null && report.generated_at !== null),
      // Estrai il report (ormai non null)
      map(report => report as GeneratedReport),
      // Prendi il primo e completa
      take(1)
    );
  }
}
