// services/report.service.ts
import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable, from, switchMap } from 'rxjs';
import { TimbratureSupabaseService } from './timbrature-supabase.service';
import { GeneratedReport } from '../models';
import { GeneratedReportsService } from './generated-reports.service';
import { AuthService } from './timbrature-auth.adapter';

export interface ReportFilters {
  startDate?: string;
  endDate?: string;
  employeeIds?: string[];
  departmentIds?: string[];
  // altri filri
}

@Injectable({ providedIn: 'root' })
export class ReportService {
  private auth = inject(AuthService);
  private generatedReports = inject(GeneratedReportsService);
  private supabase = inject(TimbratureSupabaseService).getSupabaseClient();
  private http = inject(HttpClient);
  private baseUrl = '/api/reports'; 

  // URL della Edge Function (da configurare in environment)
  private reportFunctionUrl = 'https://<progetto>.supabase.co/functions/v1/generate-report';

  /**
   * Richiede la generazione di un report.
   * Restituisce un Observable con l'ID del report richiesto.
   */
  requestReport(reportType: string, filters: ReportFilters, format: 'pdf' | 'xlsx' | 'csv'): Observable<{ reportId: string }> {
    // Prepara i parametri includendo i dati dell'utente/azienda
    const user = this.auth.currentUserSubject.value;
    if (!user) throw new Error('Utente non autenticato');

    const payload = {
      reportType,
      format,
      filters,
      companyId: this.auth.companyId,
      requestedBy: user.id
    };

    // Ottieni il token JWT per autorizzare la chiamata all'Edge Function
    return from(this.auth.getToken()).pipe(
      switchMap(token => {
        const headers = new HttpHeaders({
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        });
        return this.http.post<{ reportId: string }>(this.reportFunctionUrl, payload, { headers });
      })
    );
  }

  /**
   * Monitora lo stato di un report fino al completamento.
   * Restituisce il record completo di `generated_reports`.
   */
  waitForReport(reportId: string): Observable<GeneratedReport> {
    return this.generatedReports.waitForReport(reportId);
  }

  /**
   * Ottiene l'URL firmato per il download del report.
   * Il file_path è del tipo 'nomecartella/nomefile.pdf' (relativo al bucket).
   */
  async getDownloadUrl(report: GeneratedReport): Promise<string> {
    if (!report.file_path) throw new Error('Report non ancora generato');
    const { data, error } = await this.supabase.storage
      .from('reports') // nome del bucket
      .createSignedUrl(report.file_path, 60 * 5); // URL valido 5 minuti
    if (error) throw error;
    return data.signedUrl;
  }

  /**
   * Avvia il download diretto del report (apre una nuova finestra o triggera il download).
   */
  async downloadReport(report: GeneratedReport): Promise<void> {
    const url = await this.getDownloadUrl(report);
    window.open(url, '_blank');
  }

  /**
   * (Opzionale) Metodo per generare un report semplice lato client
   * se i dati sono pochi e non si vuole chiamare il server.
   */
  generateSimpleReportLocally(filters: ReportFilters): Observable<Blob> {
    // Esempio: recupera i dati da timbrature via BaseService e crea un file
    // ...
    // Restituisce un Blob
    return new Observable();
  }

  /**
   * Esporta il report in formato PDF/XLSX/CSV (chiamata sincrona che restituisce blob).
   */
  exportReport(format: 'pdf' | 'xlsx', filters: any): Observable<Blob> {
    return from(this.auth.getToken()).pipe(
      switchMap(token => {
        const headers = new HttpHeaders({
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        });
        return this.http.post(`${this.baseUrl}/export`, { ...filters, format }, {
          headers,
          responseType: 'blob'
        });
      })
    );
  }

}
